// 倒序容斥
void solve(int CASE)
{
	ll a, b, c, m; cin >> a >> b >> c >> m;
	ll _3 = Math::lcm(a, Math::lcm(b, c));
	array<ll, 3> _2 = { Math::lcm(a,b),Math::lcm(b,c),Math::lcm(a,c) };
	var sum = Vec2<ll>(3, 3);

	ll tmp = m / _3;
	fa(i, 0, 2)sum[i][2] += tmp; // 只有 abc 同时在拿权值 

  	// 只有 ab、bc、ac 同时在拿权值 
	fa(i, 0, 2) {
		ll tmp = m / _2[i];
		if (i == 0) {
			sum[0][1] += tmp - sum[0][2];
			sum[1][1] += tmp - sum[1][2];
		}
		else if (i == 1) {
			sum[1][1] += tmp - sum[1][2];
			sum[2][1] += tmp - sum[2][2];
		}
		else {
			sum[0][1] += tmp - sum[0][2];
			sum[2][1] += tmp - sum[2][2];
		}
	}

  	// 只有 a、b、c 在拿权值 
	tmp = m / a;
	sum[0][0] = tmp - sum[0][1] - sum[0][2];
	tmp = m / b;
	sum[1][0] = tmp - sum[1][1] - sum[1][2];
	tmp = m / c;
	sum[2][0] = tmp - sum[2][1] - sum[2][2];

	fa(i, 0, 2) {
		ll ans = sum[i][0] * 6 + sum[i][1] * 3 + sum[i][2] * 2;
		cout << ans << ' ';
	}cout << endl;
	return;
}
